{
  "name": "3SquaresVT",
  "eligibility": {
    "age": 60,
    "income_limits": "Households with anyone age 60+ or disabled do not need to meet the gross income limit (185% FPL). Net income must be at or below 185% FPL based on household size (specific dollar table not in sources; refer to official guidelines). If gross income exceeds 185% FPL, resource test applies. Categorical eligibility if receiving SSI, Reach Up (TANF), or EITC.",
    "asset_limits": "No asset limits if income ≤185% FPL or for most households. If income >185% FPL for elderly/disabled households: $4,500 limit (sources vary: $4,500[1], $4,250[6], $3,500[3]). Counts: savings, checking, investments. Exempt: primary home, primary vehicle, retirement/educational savings accounts (e.g., 401k, IRA).",
    "other_requirements": ["U.S. citizen or qualified non-citizen (5-year residency or work history/ humanitarian status)", "Work requirements may apply (exempt for 60+, disabled, caregivers; Time-Limited Benefit Requirement for 18-64 unless exempt[2])", "Vermont resident"]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly benefits loaded on EBT card for food purchases. Average $180/month for older Vermonter living alone[4]. Higher if medical expenses (OTC meds, premiums, supplies, dentures, prescriptions, home health aid)[1]. Cash deposit to bank account or cash on EBT if all household 65+[1].",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Online: myBenefits portal (https://mybenefits.vermont.gov/)[4]", "Phone: Helpline 1-800-642-5119[4]", "Mail/print simplified form for 60+ or disabled without earned income, return to district office[4]", "In-person: District offices or Age Well assistance"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["Simplified application for 60+ or disabled without earned income[4]", "210A form for work requirement personal barrier exemption[2]"],
    "documents": ["Proof of income, expenses (esp. medical), identity, residency, SSI/ disability if applicable (sources do not list exhaustively; prepare bank statements, bills)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": ["District offices (statewide)", "Age Well (1-800-642-5119)[4]"]
  },
  "official_source": "https://mybenefits.vermont.gov/",
  "gotchas": ["Asset test only triggers if income >185% FPL for elderly/disabled (missed by many)[1][6]", "Cash benefits only if all household 65+[1]", "Work requirements expanded in 2025 to age 64 (exemptions available via 210A form)[2]", "Medical expenses can increase benefits[1]", "Certification up to 3 years for 65+/disabled[1]", "No resource limit for most, even with savings/home/car[1][5]"],
  "data_shape_notes": "Elderly/disabled special rules: no gross income test, conditional asset test, cash option for 65+ households, medical deductions boost benefits, simplified application"
}

{
  "name": "Weatherization Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "Varies by county and household size (1-8 persons) based on prior 12 months gross income, effective July 1, 2025–June 30, 2026. Addison County: 1=$65,030, 2=$74,320, 3=$83,610, 4=$92,900, 5=$100,332, 6=$107,764, 7=$115,196, 8=$122,628. Chittenden/Franklin/Grand Isle: 1=$72,695, 2=$83,080, 3=$93,465, 4=$103,850, 5=$112,158, 6=$120,466, 7=$128,774, 8=$137,082. Rest of State: 1=$62,580, 2=$71,520, 3=$80,460, 4=$89,400, 5=$96,552, 6=$103,704, 7=$110,856, 8=$118,008. WRAP targets moderate-income <120% area median income with 12 months on-time utility payments.[2][4]",
    "asset_limits": "No asset limits mentioned; WRAP underwriting based on utility payment history, not credit score or assets.[1][5]",
    "other_requirements": ["Household must be low- to moderate-income.", "For WRAP: Electric/gas account with participating utility (e.g., Green Mountain Power, Vermont Gas, Burlington Electric, Vermont Electric Coop), 12 months on-time payments, upgrades must yield ≥10% net energy savings.[1][5]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free home insulation and air sealing via community action agencies (BROC, Capstone, CVOEO, NETO, SEVCA). WRAP finances up to 75% of costs (capped $20,000/project, avg $7,000 financed) for insulation/air sealing, heat pumps, electric water heaters, advanced wood heating; repaid via utility bill tariff (e.g., 2% interest up to 15 years, or 60 months for VGS); avg $60/month savings vs $52 payment; combines with rebates/incentives up to $1,500 VHFA + $6,000 WRAP.[1][3][4]",
    "varies_by": "priority_tier|region"
  },
  "application": {
    "methods": ["Contact community action agencies for free weatherization (BROC, Capstone, CVOEO, NETO, SEVCA). For WRAP: Schedule home energy evaluation via Efficiency Vermont, Vermont Gas Systems, or Burlington Electric Department; Vermont Gas: vgsvt.com/weatherization-repayment-assistance-program; Efficiency Vermont: efficiencyvermont.com.[3][4][5]"],
    "processing_time": "Not specified.",
    "waitlist": null,
    "forms": [],
    "documents": ["Proof of prior 12 months gross income.", "Utility bill payment history (for WRAP).[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Income limits vary by county (Addison, Chittenden/Franklin/Grand Isle, rest of state); WRAP limited to participating utilities.[2][5]",
    "regional_variations": "Income guidelines differ by county; delivered via 5 regional community action agencies; WRAP admins: Efficiency Vermont (most), Vermont Gas (VGS customers), Burlington Electric (non-VGS BED).[2][3][5]",
    "offices_or_providers": ["BROC", "Capstone", "CVOEO", "NETO", "SEVCA", "Efficiency Vermont", "Vermont Gas Systems", "Burlington Electric Department"]
  },
  "official_source": "https://outside.vermont.gov/dept/DCF/Shared%20Documents/Benefits/Weatherization-Income-Guidelines.pdf",
  "gotchas": ["Two main tracks: Free service via community agencies (strict low-income) vs WRAP financing (moderate-income, utility-tied repayment stays with meter even if renter moves/sells). WRAP requires ≥10% savings projection and good utility history, not credit. Not all utilities participate. Renters eligible but benefits meter-tied.[1][3][4][5]"],
  "data_shape_notes": "Income limits county-specific table; free services via 5 regional agencies; WRAP financing utility-specific with repayment on bill, no credit check, moderate-income focus."
}

{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries regardless of income[4][5]",
    "asset_limits": "No asset limits; no asset test applies[4]",
    "other_requirements": ["Must be a Medicare beneficiary (includes individuals 65+, younger adults with disabilities, those with End-Stage Renal Disease (ESRD))[5]", "Caregivers and families of Medicare beneficiaries are also eligible[4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, personalized one-on-one health insurance counseling and education on Medicare benefits, coverage decisions, Medicare Advantage plans, Part D prescription drugs, Medigap, Medicaid eligibility, long-term care insurance, appeals/denials, and other health insurance issues; also includes group education presentations and outreach[1][4][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-800-642-5119 (in-state), (802) 225-6210 (out-of-state), Local (802) 865-0360[1][2][3]", "Website: http://www.vermont4a.org/[1]", "Email: Donna@vermont4a.org or info@nekcouncil.org (for NEK region)[1][3]", "In-person: Through local providers like Vermont Association of Area Agencies on Aging (476 Main Street, Suite #3, Winooski VT 05404) or NEK Council on Aging[1][3]"],
    "processing_time": "Immediate counseling available via phone or appointment; no formal application processing[1][4]",
    "waitlist": null,
    "forms": ["No specific forms required; counseling provided directly upon contact[4]"],
    "documents": ["Medicare card, current insurance details, prescription lists, and denial letters if applicable (recommended for personalized help, but not mandatory to start)[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered statewide by Vermont Association of Area Agencies on Aging with local affiliates like NEK Council on Aging providing regionally focused counseling; services reflect local Medicare options and resources, but core services uniform[1][3][4]",
    "offices_or_providers": ["Vermont Association of Area Agencies on Aging (Winooski)[1]", "NEK Council on Aging (Northeast Kingdom region)[3]"]
  },
  "official_source": "https://www.vermont4a.org/",
  "gotchas": ["Not a healthcare or financial benefit program—provides only free counseling, not direct payments or medical services[4][6]", "People often confuse it with Medicare Savings Programs; SHIP helps apply for those but is not one itself[6]", "Services are free with no income test, but targeted outreach prioritizes underserved populations[4]", "Relies on trained staff/volunteers; availability may depend on local affiliate capacity[4]"],
  "data_shape_notes": "no income or asset test; counseling-only service delivered via statewide network with local affiliates; open to all Medicare beneficiaries and families"
}

{
  "name": "Vermont Legal Aid Elder Law Project",
  "eligibility": {
    "age": 60,
    "income_limits": "No income restrictions; eligibility not restricted by income level, though general Vermont Legal Aid programs (which may overlap) use 200% of federal poverty level (e.g., $48,600 for family of 4 as of 2019 data)[1][2]",
    "asset_limits": "No asset limits mentioned; not applicable based on available information[1][2]",
    "other_requirements": ["Vermont resident", "Civil legal problems relevant to seniors (priority on housing, financial exploitation, Social Security, Medicaid, guardianship)", "Case priority given to those at risk[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Full range of civil legal services including direct representation, legal advice, Medicare appeals; priority areas: housing, financial exploitation, Social Security, Medicaid, guardianship[1][2]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: 1-800-889-2047[1][2][3][4]", "Online: VTLawHelp.org Legal Help Tool (select Seniors category for elder law specialist), Legal Help Request Form[3][4][7]", "In-person: Six regional offices across Vermont (contact central intake for locations)[1]"],
    "processing_time": "Not specified in sources",
    "waitlist": null,
    "forms": ["Legal Help Request Form on VTLawHelp.org[3][4]"],
    "documents": ["Not explicitly listed; prepare details on legal issue, personal info for intake (name, phone); income details may be requested for general VLA but not required for Elder Law Project[1][2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; serves Vermonters statewide",
    "regional_variations": "Staff located in six regional offices, but centralized intake; no specific differences in services, wait times, or providers by region noted[1]",
    "offices_or_providers": ["Six regional offices (contact 1-800-889-2047 for details)[1]"]
  },
  "official_source": "https://www.vtlegalaid.org[6]",
  "gotchas": ["Not restricted by income/assets unlike general VLA (200% FPL) or other projects; focuses on civil matters only (no criminal, traffic); priority on specific senior issues—may not take all cases; separate from Medicare Advocacy Project but includes Medicare appeals[1][2][4]", "Must specify elder law/seniors in intake for specialist routing[7]", "Overlaps with Disability Law Project if disability-related[1]"],
  "data_shape_notes": "No income/asset test for seniors 60+; priority-based case acceptance; statewide with regional offices but unified intake; distinct from income-tested general legal aid[1][2]"
}

{
  "name": "Vermont Senior Companion Program",
  "eligibility": {
    "age": 55,
    "income_limits": "Based on 200% of federal poverty guidelines. Examples: $31,300 or less for a single person, $42,300 or less for a couple (202? guidelines from [1]); $27,180 (1), $36,620 (2), $46,060 (3), $55,500 (4) for 2022 [2]; $30,120 (single), $40,880 (couple), $51,640 (family of 3), $62,400 (family of 4) from another source [4]. Exact current amounts vary by year; contact agency for 2026 guidelines.",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Able to serve at least 10 hours per week (up to 40 hours)", "Resident of Vermont"]
  },
  "benefits": {
    "type": "service",
    "value": "Non-financial companionship and assistance services to elderly clients, provided by eligible Senior Companions (age 55+ low-income volunteers). Services include: friendly visits, listening, errands, rides, help with shopping or paying bills, promoting independence at home, respite for family caregivers. Companions receive: $4.00/hour non-taxable stipend (does not affect benefits like 3SquaresVT or subsidized housing), $0.70/mile mileage reimbursement, flexible schedule (10-40 hours/week), monthly gatherings, ongoing training (4 hours/month average), support.",
    "varies_by": "fixed"
  },
  "application": {
    "methods": [
      "Contact Vermont’s Area Agencies on Aging: Age Well (www.agewellvt.org), Northeast Kingdom Council on Aging (www.nekcouncil.org), Senior Solutions (www.seniorsolutionsvt.org), Southwestern Vermont Council on Aging (www.svcoa.org)",
      "Call Helpline: 1-800-642-5119"
    ],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["Not specified; apply through agencies"],
    "documents": ["Proof of age, income verification (to confirm eligibility as volunteer)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide through 4 Area Agencies on Aging.",
    "regional_variations": "Administered by 4 regional agencies (Age Well, NEK Council on Aging, Senior Solutions, SVCOA), but no differences in eligibility, benefits, or services noted.",
    "offices_or_providers": ["Age Well (www.agewellvt.org)", "Northeast Kingdom Council on Aging (www.nekcouncil.org)", "Senior Solutions (www.seniorsolutionsvt.org)", "Southwestern Vermont Council on Aging (www.svcoa.org)"]
  },
  "official_source": "No single primary .gov URL; program administered via https://vermontmaturity.com (state-affiliated) and 4 Area Agencies on Aging websites.",
  "gotchas": [
    "This is a **volunteer program** for low-income seniors (55+) to provide companionship services to other elderly; families do not 'apply' to receive services directly—instead, request companions through agencies. Not a direct benefit for the elderly loved one.",
    "Income eligibility for companions only; clients (elderly receiving help) have no stated eligibility requirements in sources.",
    "Income guidelines outdated in sources (2022 or earlier); verify current federal poverty levels x200% with agency.",
    "Stipend is non-taxable and does not affect recipient's benefits, but for companions only.",
    "No info on processing times, waitlists, or client application process."
  ],
  "data_shape_notes": "Volunteer companion program (AmeriCorps Seniors), not direct aid to elderly; eligibility/income for volunteers only; statewide via 4 regional agencies; income at 200% poverty level (varies yearly, examples by household size provided); no client-side eligibility detailed."
}
